// execPromptCapBytes caps the size of inline prompt env-var values
// (DDX_AGENT_PROMPT) carried by exec definitions. FEAT-022 §9 / Stage D2.
// Package-level variable so tests can lower the cap; production callers
// must not mutate it.
var execPromptCapBytes = evidence.DefaultMaxPromptBytes

// loadDefinitions returns all definitions and the doc graph built during loading.
// The graph may be nil if graph loading failed (soft error treated as empty).
func (s *Store) loadDefinitions() ([]Definition, *docgraph.Graph, error) {
	defs := make(map[string]Definition)

	// Graph-authored definitions take precedence over runtime-managed ones.
	// The graph is returned so callers can reuse it without a second build.
	graph, graphDefs, _ := s.loadGraphDefinitions()
	for _, def := range graphDefs {
		if def.ID == "" || !def.Active {
			continue
		}
		defs[def.ID] = def
	}

	if s.DefinitionCollection != nil {
		beads, err := s.DefinitionCollection.ReadAll()
		if err != nil {
			return nil, nil, err
		}
		for _, entry := range beads {
			def, err := definitionFromBead(entry)
			if err != nil {
				return nil, nil, err
			}
			if def.ID == "" || !def.Active {
				continue
			}
			if _, ok := defs[def.ID]; ok {
				continue // graph-authored takes precedence
			}
			defs[def.ID] = def
		}
	}

	legacy, err := s.readLegacyDefinitions()
	if err != nil {
		return nil, nil, err
	}
	for _, def := range legacy {
		if def.ID == "" || !def.Active {
			continue
		}
		if _, ok := defs[def.ID]; ok {
			continue
		}
		defs[def.ID] = def
	}

	out := make([]Definition, 0, len(defs))
	for _, def := range defs {
		if prompt, ok := def.Executor.Env["DDX_AGENT_PROMPT"]; ok {
			if observed := len([]byte(prompt)); observed > execPromptCapBytes {
				return nil, nil, fmt.Errorf(
					"exec definition %q env DDX_AGENT_PROMPT exceeds cap: observed %d bytes, cap %d bytes (configurable via .ddx/config.yaml:evidence_caps.max_prompt_bytes)",
					def.ID, observed, execPromptCapBytes)
			}
		}
		out = append(out, def)
	}
	sort.Slice(out, func(i, j int) bool {
		if out[i].CreatedAt.Equal(out[j].CreatedAt) {
			return out[i].ID < out[j].ID
		}
		return out[i].CreatedAt.After(out[j].CreatedAt)
	})
	return out, graph, nil
}

// loadGraphDefinitions builds the doc graph and extracts exec definitions
// embedded in document frontmatter via the exec: block.
// Returns the built graph so callers can reuse it without a second walk.
func (s *Store) loadGraphDefinitions() (*docgraph.Graph, []Definition, error) {
	graph, err := s.buildGraph()
	if err != nil {
		return nil, nil, err
	}
	var defs []Definition
	for _, doc := range graph.Documents {
		if doc.ExecDef == nil {
			continue
		}
		ed := doc.ExecDef
		// ArtifactIDs: prefer the explicit list; fall back to the document's depends_on.
		artifactIDs := append([]string{}, ed.ArtifactIDs...)
		if len(artifactIDs) == 0 {
			artifactIDs = append(artifactIDs, doc.DependsOn...)
		}
		def := Definition{
			ID:          doc.ID,
			ArtifactIDs: artifactIDs,
			Executor: ExecutorSpec{
				Kind:      ed.Kind,
				Command:   ed.Command,
				Cwd:       ed.Cwd,
				Env:       ed.Env,
				TimeoutMS: ed.TimeoutMS,
			},
			Required:    ed.Required,
			Active:      ed.Active,
			GraphSource: true,
		}
		if ed.Comparison != "" || ed.Thresholds != nil {
			def.Evaluation = Evaluation{Comparison: ed.Comparison}
			if ed.Thresholds != nil {
				def.Evaluation.Thresholds = Thresholds{
					WarnMS:    ed.Thresholds.Warn,
					RatchetMS: ed.Thresholds.Ratchet,
				}
			}
		}
		if ed.Metric != nil {
			def.Result.Metric = &MetricResultSpec{
				Unit: ed.Metric.Unit,
			}
		}
		defs = append(defs, def)
	}
	return graph, defs, nil
}

func (s *Store) readLegacyDefinitions() ([]Definition, error) {
	entries, err := os.ReadDir(s.DefinitionsDir)
	if err != nil {
		if os.IsNotExist(err) {
			return nil, nil
		}
		return nil, err
	}

	defs := make([]Definition, 0, len(entries))
	for _, entry := range entries {
		if entry.IsDir() || !strings.HasSuffix(strings.ToLower(entry.Name()), ".json") {
			continue
		}
		raw, err := os.ReadFile(filepath.Join(s.DefinitionsDir, entry.Name()))
		if err != nil {
			return nil, err
		}
		var def Definition
		if err := json.Unmarshal(raw, &def); err != nil {
			return nil, fmt.Errorf("parse exec definition %q: %w", entry.Name(), err)
		}
		defs = append(defs, def)
	}
	return defs, nil
}

func (s *Store) loadRuns() ([]RunRecord, error) {
	runs := make(map[string]RunRecord)

	if s.RunCollection != nil {
		beads, err := s.RunCollection.ReadAll()
		if err != nil {
			return nil, err
		}
		for _, entry := range beads {
			rec, err := s.runRecordFromBead(entry)
			if err != nil {
				return nil, err
			}
			if rec.RunID == "" {
				continue
			}
			runs[rec.RunID] = rec
		}
	}

	legacy, err := s.readLegacyRuns()
	if err != nil {
		return nil, err
	}
	for _, rec := range legacy {
		if rec.RunID == "" {
			continue
		}
		if _, ok := runs[rec.RunID]; ok {
			continue
		}
		runs[rec.RunID] = rec
	}

	out := make([]RunRecord, 0, len(runs))
	for _, rec := range runs {
		out = append(out, rec)
	}
	sort.Slice(out, func(i, j int) bool {
		if out[i].StartedAt.Equal(out[j].StartedAt) {
			return out[i].RunID < out[j].RunID
		}
		return out[i].StartedAt.Before(out[j].StartedAt)
	})
	return out, nil
}

func (s *Store) readLegacyRuns() ([]RunRecord, error) {
	entries, err := os.ReadDir(s.RunsDir)
	if err != nil {
		if os.IsNotExist(err) {
			return nil, nil
		}
		return nil, err
	}

	records := make([]RunRecord, 0, len(entries))
	for _, entry := range entries {
		if !entry.IsDir() || strings.HasPrefix(entry.Name(), ".tmp-") {
			continue
		}
		rec, err := s.readRunBundle(filepath.Join(s.RunsDir, entry.Name()))
		if err != nil {
			return nil, err
		}
		records = append(records, rec)
	}
	return records, nil
}

func (s *Store) loadRunByID(runID string) (RunRecord, error) {

// get the terser claude variant; the embedded Fizeau harness gets the
// fuller agent variant with explicit tool names and stop-after-commit
// scaffolding.
func executeBeadInstructionsText(harness string) string {
	switch strings.ToLower(strings.TrimSpace(harness)) {
	case "agent", "fiz", "embedded":
		return executeBeadInstructionsAgentText
	default:
		return executeBeadInstructionsClaudeText
	}
}

// executeBeadMissingGoverningText is emitted inside <governing> when no
// governing references were pre-resolved for the bead. The bead description
// is the primary contract — this note only reminds the agent to treat it as
// such and to ground any unclear decisions in repository state rather than
// guessing.
const executeBeadMissingGoverningText = `No governing references were pre-resolved. The bead description above is the primary contract. If it names files, specs, or prior beads, read those before editing. Ground decisions in what is already in the repository; do not guess.`

func xmlEscape(s string) string {
	var buf bytes.Buffer
	_ = xml.EscapeText(&buf, []byte(s))
	return buf.String()
}

func xmlAttrEscape(s string) string {
	r := strings.NewReplacer(
		"&", "&amp;",
		"<", "&lt;",
		">", "&gt;",
		"\"", "&quot;",
		"'", "&apos;",
		"\n", "&#10;",
		"\r", "&#13;",
		"\t", "&#9;",
	)
	return r.Replace(s)
}

func buildPrompt(workDir string, b *bead.Bead, refs []executeBeadGoverningRef, artifacts *executeBeadArtifacts, baseRev, promptOverride, harness string, contextBudget string) ([]byte, string, error) {
	if strings.TrimSpace(promptOverride) != "" {
		path := promptOverride
		if !filepath.IsAbs(path) {
			path = filepath.Join(workDir, path)
		}
		data, err := readPromptFileBounded(path)
		if err != nil {
			return nil, "", fmt.Errorf("reading prompt override %q: %w", promptOverride, err)
		}
		return data, promptOverride, nil
	}

	var sb strings.Builder
	sb.WriteString("<execute-bead>\n")

	instructions := strings.ReplaceAll(executeBeadInstructionsText(harness), "{{.AttemptDir}}", artifacts.DirRel)
	// Put the largely static instructions first so prefix caches can reuse as
	// much of the prompt as possible before the bead-specific XML starts.
	fmt.Fprintf(&sb, "  <instructions>\n%s\n  </instructions>\n", xmlEscape(instructions))

	fmt.Fprintf(&sb, "  <bead id=\"%s\">\n", xmlAttrEscape(b.ID))
	fmt.Fprintf(&sb, "    <title>%s</title>\n", xmlEscape(strings.TrimSpace(b.Title)))

	desc := strings.TrimSpace(b.Description)
	if desc == "" {
		sb.WriteString("    <description/>\n")
	} else {
		fmt.Fprintf(&sb, "    <description>\n%s\n    </description>\n", xmlEscape(desc))
	}

	acc := strings.TrimSpace(b.Acceptance)
	if acc == "" {
		sb.WriteString("    <acceptance/>\n")
	} else {
		fmt.Fprintf(&sb, "    <acceptance>\n%s\n    </acceptance>\n", xmlEscape(acc))
	}

	// Bead notes carry review findings from prior iterations, escalation
	// context, or operator hints that did not fit into the description at
	// creation time. Threading them into the prompt as a distinct section
	// lets the agent act on them without the operator having to rewrite the
	// description in place on every reopen.
	if notes := strings.TrimSpace(b.Notes); notes != "" {
		fmt.Fprintf(&sb, "    <notes>\n%s\n    </notes>\n", xmlEscape(notes))
	}

	if len(b.Labels) > 0 {
		fmt.Fprintf(&sb, "    <labels>%s</labels>\n", xmlEscape(strings.Join(b.Labels, ", ")))
	} else {
		sb.WriteString("    <labels/>\n")
	}

	metaAttrs := make([]string, 0, 6)
	if b.Parent != "" {
		metaAttrs = append(metaAttrs, fmt.Sprintf("parent=\"%s\"", xmlAttrEscape(b.Parent)))
	}
	if specID, _ := b.Extra["spec-id"].(string); strings.TrimSpace(specID) != "" {
		metaAttrs = append(metaAttrs, fmt.Sprintf("spec-id=\"%s\"", xmlAttrEscape(strings.TrimSpace(specID))))
	}
	metaAttrs = append(metaAttrs, fmt.Sprintf("base-rev=\"%s\"", xmlAttrEscape(baseRev)))
	metaAttrs = append(metaAttrs, fmt.Sprintf("bundle=\"%s\"", xmlAttrEscape(artifacts.DirRel)))
	fmt.Fprintf(&sb, "    <metadata %s/>\n", strings.Join(metaAttrs, " "))
	sb.WriteString("  </bead>\n")

	// For minimal budget, omit full governing refs and only include bead metadata.
	// This significantly reduces prompt size for cheap-tier attempts on local models.
	if contextBudget == "minimal" {
		sb.WriteString("  <governing>\n    <note>No governing references.</note>\n  </governing>\n")
	} else {
		if len(refs) == 0 {
			fmt.Fprintf(&sb, "  <governing>\n    <note>%s</note>\n  </governing>\n", xmlEscape(executeBeadMissingGoverningText))
		} else {
			sb.WriteString("  <governing>\n")
			for _, ref := range refs {
				attrs := fmt.Sprintf("id=\"%s\" path=\"%s\"", xmlAttrEscape(ref.ID), xmlAttrEscape(ref.Path))
				if strings.TrimSpace(ref.Title) == "" {
					fmt.Fprintf(&sb, "    <ref %s/>\n", attrs)
				} else {
					fmt.Fprintf(&sb, "    <ref %s>%s</ref>\n", attrs, xmlEscape(strings.TrimSpace(ref.Title)))
				}
			}
			sb.WriteString("  </governing>\n")
		}
	}

	sb.WriteString("</execute-bead>\n")

	return []byte(sb.String()), "synthesized", nil
}

// promptSHA returns the hex-encoded sha256 of the rendered prompt bytes.
// Used as manifest.prompt_sha so analytics can group attempts by the exact
// prompt that produced them.
func promptSHA(promptContent []byte) string {
	sum := sha256.Sum256(promptContent)
	return hex.EncodeToString(sum[:])
}

